/// Returns the integer formed by reversing the decimal digits of `n`.
///
/// Precondition: `n >= 0`.
/// Leading zeros produced by the reversal are dropped, because parsing the
/// reversed string back into an `Int` ignores them (e.g. "0021" -> 21).
///
/// Examples:
///   reverse_digits(1230) == 321
///   reverse_digits(100)  == 1
///   reverse_digits(7)    == 7
pub fn reverse_digits(n: Int) -> Int {
  let reversed =
    n
    |> int.to_string
    |> string.reverse
    |> int.parse

  case reversed {
    Ok(value) -> value
    // Unreachable for n >= 0: a non-empty string of digits always parses.
    Error(_) -> 0
  }
}

