) -> #(Int, List(String)) {
  case tokens {
    ["+", ..rest] -> {
      let #(right, rest2) = parse_term(rest)
      parse_expr_loop(acc + right, rest2)
    }
    ["-", ..rest] -> {
      let #(right, rest2) = parse_term(rest)
      parse_expr_loop(acc - right, rest2)
    }
    _ -> #(acc, tokens)
  }
}

/// term := factor (('*' | '/') factor)*
fn parse_term(tokens: List(String)) -> #(Int, List(String)) {
  let #(left, rest) = parse_factor(tokens)
  parse_term_loop(left, rest)
}

fn parse_term_loop(
  acc: Int,
  tokens: List(String),
) -> #(Int, List(String)) {
  case tokens {
    ["*", ..rest] -> {
      let #(right, rest2) = parse_factor(rest)
      parse_term_loop(acc * right, rest2)
    }
    ["/", ..rest] -> {
      let #(right, rest2) = parse_factor(rest)
      case int.divide(acc, right) {
        Ok(q) -> parse_term_loop(q, rest2)
        Error(_) -> panic as "division by zero in expression"
      }
    }
    _ -> #(acc, tokens)
  }
}

/// factor := number | '(' expr ')'
fn parse_factor(tokens: List(String)) -> #(Int, List(String)) {
  case tokens {
    ["(", ..rest] -> {
      let #(value, rest2) = parse_expr(rest)
      case rest2 {
        [")", ..rest3] -> #(value, rest3)
        _ -> panic as "missing closing parenthesis"
      }
    }
    [first, ..] ->
      case is_digit(first) {
        True -> parse_number(tokens, 0)
        False -> panic as "expected a number or '('"
      }
    [] -> panic as "unexpected end of input"
  }
}

/// Consumes a run of digit graphemes, building up the integer value.
fn parse_number(
  tokens: List(String),
  acc: Int,
) -> #(Int, List(String)) {
  case tokens {
    [first, ..rest] ->
      case digit_value(first) {
        Ok(d) -> parse_number(rest, acc * 10 + d)
        Error(_) -> #(acc, tokens)
      }
    [] -> #(acc, tokens)
  }
}

fn is_digit(grapheme: String) -> Bool {
  case digit_value(grapheme) {
    Ok(_) -> True
    Error(_) -> False
  }
}

fn digit_value(grapheme: String) -> Result(Int, Nil) {
  case grapheme {
    "0" -> Ok(0)
    "1" -> Ok(1)
    "2" -> Ok(2)
    "3" -> Ok(3)
    "4" -> Ok(4)
    "5" -> Ok(5)
    "6" -> Ok(6)
    "7" -> Ok(7)
    "8" -> Ok(8)
    "9" -> Ok(9)
    _ -> Error(Nil)
  }
}

