(* Integer arithmetic expression evaluator.
   Grammar (recursive descent):
     expr   = term { ("+" | "-") term } .
     term   = factor { ("*" | "/") factor } .
     factor = number | "(" expr ")" .
   Precedence: * / bind tighter than + - ; all operators left-associative.
   Input: non-negative integer literals, operators + - * /, parentheses, no spaces. *)

  VAR
    str: ARRAY 256 OF CHAR;  (* expression being parsed *)
    pos: INTEGER;            (* current scan position into str *)

  PROCEDURE Cur(): CHAR;
  (* Returns the current character, or 0X at end of input. *)
  BEGIN
    IF str[pos] = 0X THEN RETURN 0X ELSE RETURN str[pos] END
  END Cur;

  PROCEDURE^ ParseExpr(): INTEGER;

  PROCEDURE ParseFactor(): INTEGER;
    VAR n: INTEGER; c: CHAR;
  BEGIN
    c := Cur();
    IF c = "(" THEN
      INC(pos);            (* consume "(" *)
      n := ParseExpr();
      IF Cur() = ")" THEN INC(pos) END  (* consume ")" *)
    ELSE
      (* read a non-negative integer literal *)
      n := 0;
      WHILE (Cur() >= "0") & (Cur() <= "9") DO
        n := n * 10 + (ORD(Cur()) - ORD("0"));
        INC(pos)
      END
    END;
    RETURN n
  END ParseFactor;

  PROCEDURE ParseTerm(): INTEGER;
    VAR result, rhs: INTEGER; op: CHAR;
  BEGIN
    result := ParseFactor();
    WHILE (Cur() = "*") OR (Cur() = "/") DO
      op := Cur();
      INC(pos);            (* consume operator *)
      rhs := ParseFactor();
      IF op = "*" THEN
        result := result * rhs
      ELSE
        result := result DIV rhs
      END
    END;
    RETURN result
  END ParseTerm;

  PROCEDURE ParseExpr(): INTEGER;
    VAR result, rhs: INTEGER; op: CHAR;
  BEGIN
    result := ParseTerm();
    WHILE (Cur() = "+") OR (Cur() = "-") DO
      op := Cur();
      INC(pos);            (* consume operator *)
      rhs := ParseTerm();
      IF op = "+" THEN
        result := result + rhs
      ELSE
        result := result - rhs
      END
    END;
    RETURN result
  END ParseExpr;

  PROCEDURE EvalExpr*(s: ARRAY OF CHAR): INTEGER;
    VAR i: INTEGER;
  BEGIN
    (* copy input into the module-level buffer, ensuring 0X termination *)
    i := 0;
    WHILE (i < LEN(s)) & (i < LEN(str) - 1) & (s[i] # 0X) DO
      str[i] := s[i];
      INC(i)
    END;
    str[i] := 0X;
    pos := 0;
    RETURN ParseExpr()
  END EvalExpr;

END Sol.

